+        let ti = StdArc::new(ThrottleInjector::new(dev, config, 11));
+        let barrier = StdArc::new(std::sync::Barrier::new(4));
+
+        std::thread::scope(|s| {
+            for thread_id in 0_u64..4 {
+                let ti = StdArc::clone(&ti);
+                let barrier = StdArc::clone(&barrier);
+                s.spawn(move || {
+                    let cx = Cx::for_testing();
+                    barrier.wait();
+                    for i in 0..10 {
